  1â†’package csvutil
  2â†’
  3â†’import (
  4â†’	"strings"
  5â†’	"testing"
  6â†’)
  7â†’
  8â†’const csvData = `name,age,score,city
  9â†’Alice,30,9.5,New York
 10â†’Bob,25,8.1,
 11â†’Charlie,0,,Paris
 12â†’`
 13â†’
 14â†’const tsvData = "name\tage\tscore\n" +
 15â†’	"Alice\t30\t9.5\n" +
 16â†’	"Bob\t25\t8.1\n"
 17â†’
 18â†’const quotedCSV = `name,description,value
 19â†’Alice,"tall, blonde, and smart",42
 20â†’Bob,"says ""hello"" often",7
 21â†’Carol,"line1
 22â†’line2",99
 23â†’`
 24â†’
 25â†’const headerOnlyCSV = "name,age,score\n"
 26â†’
 27â†’func mustReader(t *testing.T, data string, opts ...Option) *Reader {
 28â†’	t.Helper()
 29â†’	r, err := NewReader(strings.NewReader(data), opts...)
 30â†’	if err != nil {
 31â†’		t.Fatalf("NewReader: %v", err)
 32â†’	}
 33â†’	return r
 34â†’}
 35â†’
 36â†’func collectRows(t *testing.T, r *Reader) []Row {
 37â†’	t.Helper()
 38â†’	var rows []Row
 39â†’	for {
 40â†’		row, ok, err := r.Next()
 41â†’		if err != nil {
 42â†’			t.Fatalf("Next: %v", err)
 43â†’		}
 44â†’		if !ok {
 45â†’			break
 46â†’		}
 47â†’		rows = append(rows, row)
 48â†’	}
 49â†’	return rows
 50â†’}
 51â†’
 52â†’// 1. Normal CSV parsing.
 53â†’func TestNormalCSV(t *testing.T) {
 54â†’	r := mustReader(t, csvData)
 55â†’	rows := collectRows(t, r)
 56â†’
 57â†’	if len(rows) != 3 {
 58â†’		t.Fatalf("want 3 rows, got %d", len(rows))
 59â†’	}
 60â†’
 61â†’	if got := rows[0].String("name"); got != "Alice" {
 62â†’		t.Errorf("row[0] name: want Alice, got %q", got)
 63â†’	}
 64â†’	if got := rows[0].Int("age"); got != 30 {
 65â†’		t.Errorf("row[0] age: want 30, got %d", got)
 66â†’	}
 67â†’	if got := rows[0].Float("score"); got != 9.5 {
 68â†’		t.Errorf("row[0] score: want 9.5, got %f", got)
 69â†’	}
 70â†’	if got := rows[1].String("name"); got != "Bob" {
 71â†’		t.Errorf("row[1] name: want Bob, got %q", got)
 72â†’	}
 73â†’}
 74â†’
 75â†’// 2. TSV parsing via WithDelimiter.
 76â†’func TestTSV(t *testing.T) {
 77â†’	r := mustReader(t, tsvData, WithDelimiter('\t'))
 78â†’	rows := collectRows(t, r)
 79â†’
 80â†’	if len(rows) != 2 {
 81â†’		t.Fatalf("want 2 rows, got %d", len(rows))
 82â†’	}
 83â†’	if got := rows[0].String("name"); got != "Alice" {
 84â†’		t.Errorf("row[0] name: want Alice, got %q", got)
 85â†’	}
 86â†’	if got := rows[0].Int("age"); got != 30 {
 87â†’		t.Errorf("row[0] age: want 30, got %d", got)
 88â†’	}
 89â†’	if got := rows[1].Float("score"); got != 8.1 {
 90â†’		t.Errorf("row[1] score: want 8.1, got %f", got)
 91â†’	}
 92â†’}
 93â†’
 94â†’// 3. Missing columns return zero/nil.
 95â†’func TestMissingColumn(t *testing.T) {
 96â†’	r := mustReader(t, csvData)
 97â†’	rows := collectRows(t, r)
 98â†’
 99â†’	row := rows[0]
100â†’
101â†’	if got := row.String("nonexistent"); got != "" {
102â†’		t.Errorf("missing String: want empty, got %q", got)
103â†’	}
104â†’	if got := row.Int("nonexistent"); got != 0 {
105â†’		t.Errorf("missing Int: want 0, got %d", got)
106â†’	}
107â†’	if got := row.Float("nonexistent"); got != 0 {
108â†’		t.Errorf("missing Float: want 0, got %f", got)
109â†’	}
110â†’	if got := row.OptionalString("nonexistent"); got != nil {
111â†’		t.Errorf("missing OptionalString: want nil, got %v", got)
112â†’	}
113â†’	if got := row.OptionalInt("nonexistent"); got != nil {
114â†’		t.Errorf("missing OptionalInt: want nil, got %v", got)
115â†’	}
116â†’	if got := row.OptionalFloat("nonexistent"); got != nil {
117â†’		t.Errorf("missing OptionalFloat: want nil, got %v", got)
118â†’	}
119â†’}
120â†’
121â†’// 4. Type coercion â€” Int and Float parse correctly.
122â†’func TestTypeCoercion(t *testing.T) {
123â†’	r := mustReader(t, csvData)
124â†’	rows := collectRows(t, r)
125â†’
126â†’	// row[0]: age=30, score=9.5
127â†’	if got := rows[0].Int("age"); got != 30 {
128â†’		t.Errorf("Int coercion: want 30, got %d", got)
129â†’	}
130â†’	if got := rows[0].Float("score"); got != 9.5 {
131â†’		t.Errorf("Float coercion: want 9.5, got %f", got)
132â†’	}
133â†’	// row[2]: age=0 (explicit zero), score="" (empty â†’ 0)
134â†’	if got := rows[2].Int("age"); got != 0 {
135â†’		t.Errorf("Int zero: want 0, got %d", got)
136â†’	}
137â†’	if got := rows[2].Float("score"); got != 0 {
138â†’		t.Errorf("Float empty: want 0, got %f", got)
139â†’	}
140â†’}
141â†’
142â†’// 5. Quoted values with embedded commas and newlines.
143â†’func TestQuotedValues(t *testing.T) {
144â†’	r := mustReader(t, quotedCSV)
145â†’	rows := collectRows(t, r)
146â†’
147â†’	if len(rows) != 3 {
148â†’		t.Fatalf("want 3 rows, got %d", len(rows))
149â†’	}
150â†’	if got := rows[0].String("description"); got != "tall, blonde, and smart" {
151â†’		t.Errorf("quoted comma: got %q", got)
152â†’	}
153â†’	if got := rows[1].String("description"); got != `says "hello" often` {
154â†’		t.Errorf("quoted double-quote: got %q", got)
155â†’	}
156â†’	if got := rows[2].String("description"); got != "line1\nline2" {
157â†’		t.Errorf("quoted newline: got %q", got)
158â†’	}
159â†’}
160â†’
161â†’// 6. LazyQuotes handles malformed (bare) quotes.
162â†’func TestLazyQuotes(t *testing.T) {
163â†’	data := "name,note\nAlice,she said \"hello\"\nBob,fine\n"
164â†’	r := mustReader(t, data, WithLazyQuotes(true))
165â†’	rows := collectRows(t, r)
166â†’
167â†’	if len(rows) != 2 {
168â†’		t.Fatalf("want 2 rows, got %d", len(rows))
169â†’	}
170â†’	if got := rows[0].String("name"); got != "Alice" {
171â†’		t.Errorf("lazy quote row name: got %q", got)
172â†’	}
173â†’}
174â†’
175â†’// 7. Optional accessors return nil for empty cells and missing columns.
176â†’func TestOptionalEmptyFields(t *testing.T) {
177â†’	r := mustReader(t, csvData)
178â†’	rows := collectRows(t, r)
179â†’
180â†’	// row[1]: city="" (empty)
181â†’	if got := rows[1].OptionalString("city"); got != nil {
182â†’		t.Errorf("empty OptionalString: want nil, got %v", *got)
183â†’	}
184â†’	// row[2]: score="" (empty)
185â†’	if got := rows[2].OptionalFloat("score"); got != nil {
186â†’		t.Errorf("empty OptionalFloat: want nil, got %v", *got)
187â†’	}
188â†’	// Non-empty value should not be nil.
189â†’	if got := rows[0].OptionalString("name"); got == nil || *got != "Alice" {
190â†’		t.Errorf("non-empty OptionalString: want Alice, got %v", got)
191â†’	}
192â†’	if got := rows[0].OptionalInt("age"); got == nil || *got != 30 {
193â†’		t.Errorf("non-empty OptionalInt: want 30, got %v", got)
194â†’	}
195â†’	if got := rows[0].OptionalFloat("score"); got == nil || *got != 9.5 {
196â†’		t.Errorf("non-empty OptionalFloat: want 9.5, got %v", got)
197â†’	}
198â†’}
199â†’
200â†’// 8. EOF: Next returns false, nil at end of file.
201â†’func TestEOF(t *testing.T) {
202â†’	const single = "name,age\nAlice,30\n"
203â†’	r := mustReader(t, single)
204â†’
205â†’	_, ok, err := r.Next()
206â†’	if err != nil || !ok {
207â†’		t.Fatalf("first Next: ok=%v err=%v", ok, err)
208â†’	}
209â†’	_, ok, err = r.Next()
210â†’	if err != nil {
211â†’		t.Fatalf("EOF Next returned error: %v", err)
212â†’	}
213â†’	if ok {
214â†’		t.Error("EOF Next: want ok=false")
215â†’	}
216â†’}
217â†’
218â†’// 9. Header-only file: Next immediately returns false.
219â†’func TestHeaderOnly(t *testing.T) {
220â†’	r := mustReader(t, headerOnlyCSV)
221â†’	_, ok, err := r.Next()
222â†’	if err != nil {
223â†’		t.Fatalf("header-only Next: %v", err)
224â†’	}
225â†’	if ok {
226â†’		t.Error("header-only: want ok=false on first Next")
227â†’	}
228â†’}
229â†’
230â†’// 10. NewReader returns error on bad header read.
231â†’func TestNewReaderError(t *testing.T) {
232â†’	// An empty reader has no header line â†’ should error.
233â†’	_, err := NewReader(strings.NewReader(""))
234â†’	if err == nil {
235â†’		t.Error("empty input: want error from NewReader, got nil")
236â†’	}
237â†’}
