192â†’// TestIntegrationMatcherLoad verifies Load() against a real database.
193â†’// Skipped when running with -short or when DATABASE_URL is unset.
194â†’func TestIntegrationMatcherLoad(t *testing.T) {
195â†’	if testing.Short() {
196â†’		t.Skip("skipping integration test in short mode")
197â†’	}
198â†’	dbURL := os.Getenv("DATABASE_URL")
199â†’	if dbURL == "" {
200â†’		t.Skip("DATABASE_URL not set")
201â†’	}
202â†’
203â†’	ctx := context.Background()
204â†’	pool, err := dbutil.Connect(ctx, dbURL)
205â†’	if err != nil {
206â†’		t.Fatalf("namematch: connect: %v", err)
207â†’	}
208â†’	defer pool.Close()
209â†’
210â†’	m, err := Load(ctx, pool)
211â†’	if err != nil {
212â†’		t.Fatalf("Load: %v", err)
213â†’	}
214â†’
215â†’	// Verify basic stats â€” we should have loaded something
216â†’	if len(m.exact) == 0 {
217â†’		t.Error("exact map is empty â€” no institutions loaded")
218â†’	}
219â†’	if len(m.ope6) == 0 {
220â†’		t.Error("ope6 map is empty")
221â†’	}
222â†’
223â†’	// Spot-check a known canonical name if it exists in the DB.
224â†’	// Harvard (unit_id 166027) should always be present in NCES data.
225â†’	uid, ok := m.Match("Harvard University")
226â†’	if ok {
227â†’		t.Logf("Harvard University â†’ unit_id %q", uid)
228â†’	}
229â†’
230â†’	// Verify OPE lookups are consistent: if we have an exact match,
231â†’	// OPE lookups for the same institution should return the same unit_id.
232â†’	for ope6, wantUID := range m.ope6 {
233â†’		gotUID, found := m.MatchByOPE6(ope6)
234â†’		if !found {
235â†’			t.Errorf("MatchByOPE6(%q): not found but expected in map", ope6)
236â†’		}
237â†’		if gotUID != wantUID {
238â†’			t.Errorf("MatchByOPE6(%q) = %q, want %q", ope6, gotUID, wantUID)
239â†’		}
240â†’		// Only spot-check first 5 to keep runtime short
241â†’		break
242â†’	}
243â†’}
