  8â†’func TestDeriveOpinion(t *testing.T) {
  9â†’	tests := []struct {
 10â†’		raw        string
 11â†’		wantMethod string
 12â†’		wantRank   int
 13â†’		wantScore  float64
 14â†’		wantTier   string
 15â†’		wantErr    bool
 16â†’	}{
 17â†’		// Numeric ranks
 18â†’		{raw: "1", wantMethod: "rank", wantRank: 1},
 19â†’		{raw: "42", wantMethod: "rank", wantRank: 42},
 20â†’		{raw: " 15 ", wantMethod: "rank", wantRank: 15},
 21â†’
 22â†’		// Tier strings
 23â†’		{raw: "Tier 1", wantMethod: "tier", wantTier: "Tier 1"},
 24â†’		{raw: "Tier 2", wantMethod: "tier", wantTier: "Tier 2"},
 25â†’		{raw: "tier 3", wantMethod: "tier", wantTier: "tier 3"},
 26â†’
 27â†’		// Ranges
 28â†’		{raw: "201-300", wantMethod: "range", wantRank: 251, wantTier: "201-300"},
 29â†’		{raw: "1-10", wantMethod: "range", wantRank: 6, wantTier: "1-10"},
 30â†’		{raw: "100-200", wantMethod: "range", wantRank: 150, wantTier: "100-200"},
 31â†’
 32â†’		// Decimal scores
 33â†’		{raw: "78.5", wantMethod: "score", wantScore: 78.5},
 34â†’		{raw: "99.9", wantMethod: "score", wantScore: 99.9},
 35â†’
 36â†’		// Errors
 37â†’		{raw: "", wantErr: true},
 38â†’		{raw: "N/A", wantErr: true},
 39â†’		{raw: "not ranked", wantErr: true},
 40â†’	}
 41â†’
 42â†’	for _, tt := range tests {
 43â†’		t.Run(tt.raw, func(t *testing.T) {
 44â†’			method, rank, score, tier, err := DeriveOpinion(tt.raw)
 45â†’			if tt.wantErr {
 46â†’				if err == nil {
 47â†’					t.Fatalf("expected error for %q, got method=%q", tt.raw, method)
 48â†’				}
 49â†’				return
