167â†’func contains(s, substr string) bool {
168â†’	return len(s) >= len(substr) && (s == substr || len(s) > 0 && stringContains(s, substr))
169â†’}
170â†’
171â†’func stringContains(s, substr string) bool {
172â†’	for i := 0; i <= len(s)-len(substr); i++ {
173â†’		if s[i:i+len(substr)] == substr {
174â†’			return true
175â†’		}
176â†’	}
177â†’	return false
178â†’}
