  1â†’package namematch
  2â†’
  3â†’import (
  4â†’	"encoding/json"
  5â†’	"math"
  6â†’	"os"
  7â†’	"sort"
  8â†’)
  9â†’
 10â†’// Candidate represents an institution available for fuzzy matching.
 11â†’type Candidate struct {
 12â†’	Name   string
 13â†’	UnitID string
 14â†’	State  string
 15â†’}
 16â†’
 17â†’// FuzzyResult pairs a candidate with its similarity score.
 18â†’type FuzzyResult struct {
 19â†’	Candidate
 20â†’	Score float64
 21â†’}
 22â†’
 23â†’// UnmatchedEntry records a name that could not be matched deterministically,
 24â†’// along with the best fuzzy candidates found.
 25â†’type UnmatchedEntry struct {
 26â†’	Name          string        `json:"name"`
 27â†’	StateHint     string        `json:"state_hint,omitempty"`
 28â†’	TopCandidates []FuzzyResult `json:"top_candidates"`
 29â†’}
 30â†’
 31â†’// FuzzyMatcher performs Jaro-Winkler fuzzy matching against a set of
 32â†’// institution candidates. Candidates are indexed by state for efficient
 33â†’// filtering when a state hint is available.
 34â†’type FuzzyMatcher struct {
 35â†’	all     []indexedCandidate
 36â†’	byState map[string][]indexedCandidate
 37â†’}
 38â†’
 39â†’// indexedCandidate stores a candidate alongside its pre-normalized name.
 40â†’type indexedCandidate struct {
 41â†’	Candidate
 42â†’	normalized string
 43â†’}
 44â†’
 45â†’// DefaultThreshold is the minimum Jaro-Winkler score for a match.
 46â†’const DefaultThreshold = 0.92
 47â†’
 48â†’// maxResults is the maximum number of candidates returned by Match.
 49â†’const maxResults = 5
 50â†’
 51â†’// NewFuzzyMatcher builds a FuzzyMatcher from the given candidates. Each
 52â†’// candidate's name is pre-normalized for efficient repeated comparisons.
 53â†’func NewFuzzyMatcher(candidates []Candidate) *FuzzyMatcher {
 54â†’	fm := &FuzzyMatcher{
 55â†’		all:     make([]indexedCandidate, len(candidates)),
 56â†’		byState: make(map[string][]indexedCandidate),
 57â†’	}
 58â†’	for i, c := range candidates {
 59â†’		ic := indexedCandidate{
 60â†’			Candidate:  c,
 61â†’			normalized: Normalize(c.Name),
 62â†’		}
 63â†’		fm.all[i] = ic
 64â†’		if c.State != "" {
 65â†’			fm.byState[c.State] = append(fm.byState[c.State], ic)
 66â†’		}
 67â†’	}
 68â†’	return fm
 69â†’}
 70â†’
 71â†’// Match returns the top candidates whose Jaro-Winkler similarity to name
 72â†’// exceeds DefaultThreshold, sorted by score descending. When stateHint is
 73â†’// non-empty, only candidates in that state are considered.
 74â†’func (fm *FuzzyMatcher) Match(name string, stateHint string) []FuzzyResult {
 75â†’	norm := Normalize(name)
 76â†’
 77â†’	candidates := fm.all
 78â†’	if stateHint != "" {
 79â†’		if sc, ok := fm.byState[stateHint]; ok {
 80â†’			candidates = sc
 81â†’		} else {
 82â†’			return nil
 83â†’		}
 84â†’	}
 85â†’
 86â†’	var results []FuzzyResult
 87â†’	for _, c := range candidates {
 88â†’		score := jaroWinkler(norm, c.normalized)
 89â†’		if score >= DefaultThreshold {
 90â†’			results = append(results, FuzzyResult{
 91â†’				Candidate: c.Candidate,
 92â†’				Score:     score,
 93â†’			})
 94â†’		}
 95â†’	}
 96â†’
 97â†’	sort.Slice(results, func(i, j int) bool {
 98â†’		return results[i].Score > results[j].Score
 99â†’	})
100â†’
101â†’	if len(results) > maxResults {
102â†’		results = results[:maxResults]
103â†’	}
104â†’	return results
105â†’}
106â†’
107â†’// WriteReport writes a JSON report of unmatched entries to the given path.
108â†’func WriteReport(path string, unmatched []UnmatchedEntry) error {
109â†’	data, err := json.MarshalIndent(unmatched, "", "  ")
110â†’	if err != nil {
111â†’		return err
112â†’	}
113â†’	return os.WriteFile(path, data, 0o644)
114â†’}
115â†’
116â†’// jaroWinkler computes the Jaro-Winkler similarity between two strings.
117â†’// Returns a value in [0, 1] where 1 means identical.
118â†’func jaroWinkler(s1, s2 string) float64 {
119â†’	j := jaro(s1, s2)
120â†’	if j == 0 {
121â†’		return 0
122â†’	}
123â†’
124â†’	// Winkler prefix bonus: up to 4 characters, scaling factor 0.1
125â†’	prefix := 0
126â†’	limit := 4
127â†’	if len(s1) < limit {
128â†’		limit = len(s1)
129â†’	}
130â†’	if len(s2) < limit {
131â†’		limit = len(s2)
132â†’	}
133â†’	for i := 0; i < limit; i++ {
134â†’		if s1[i] == s2[i] {
135â†’			prefix++
136â†’		} else {
137â†’			break
138â†’		}
139â†’	}
140â†’
141â†’	return j + float64(prefix)*0.1*(1-j)
142â†’}
143â†’
144â†’// jaro computes the Jaro similarity between two strings.
145â†’func jaro(s1, s2 string) float64 {
146â†’	if s1 == s2 {
147â†’		return 1
148â†’	}
149â†’	l1, l2 := len(s1), len(s2)
150â†’	if l1 == 0 || l2 == 0 {
151â†’		return 0
152â†’	}
153â†’
154â†’	// Match window: floor(max(|s1|,|s2|)/2) - 1
155â†’	maxLen := l1
156â†’	if l2 > maxLen {
157â†’		maxLen = l2
158â†’	}
159â†’	window := int(math.Floor(float64(maxLen)/2)) - 1
160â†’	if window < 0 {
161â†’		window = 0
162â†’	}
163â†’
164â†’	s1Matches := make([]bool, l1)
165â†’	s2Matches := make([]bool, l2)
166â†’
167â†’	matches := 0
168â†’	transpositions := 0
169â†’
170â†’	for i := 0; i < l1; i++ {
171â†’		lo := i - window
172â†’		if lo < 0 {
173â†’			lo = 0
174â†’		}
175â†’		hi := i + window + 1
176â†’		if hi > l2 {
177â†’			hi = l2
178â†’		}
179â†’		for j := lo; j < hi; j++ {
180â†’			if s2Matches[j] || s1[i] != s2[j] {
181â†’				continue
182â†’			}
183â†’			s1Matches[i] = true
184â†’			s2Matches[j] = true
185â†’			matches++
186â†’			break
187â†’		}
188â†’	}
189â†’
190â†’	if matches == 0 {
191â†’		return 0
192â†’	}
193â†’
194â†’	k := 0
195â†’	for i := 0; i < l1; i++ {
196â†’		if !s1Matches[i] {
197â†’			continue
198â†’		}
199â†’		for !s2Matches[k] {
200â†’			k++
201â†’		}
202â†’		if s1[i] != s2[k] {
203â†’			transpositions++
204â†’		}
205â†’		k++
206â†’	}
207â†’
208â†’	m := float64(matches)
209â†’	return (m/float64(l1) + m/float64(l2) + (m-float64(transpositions)/2)/m) / 3
210â†’}
211â†’

